import { useState } from 'react'
import { Outlet, useNavigate, useLocation } from 'react-router-dom'
import {
  Layout,
  Menu,
  Typography,
  Avatar,
  Dropdown,
  Space,
  theme,
} from 'antd'
import {
  HomeOutlined,
  FileTextOutlined,
  DatabaseOutlined,
  RobotOutlined,
  SendOutlined,
  SettingOutlined,
  UserOutlined,
  LogoutOutlined,
  MenuFoldOutlined,
  MenuUnfoldOutlined,
} from '@ant-design/icons'
import { useAuthStore } from '@/stores/authStore'

const { Header, Sider, Content, Footer } = Layout
const { Text } = Typography

// 사이드바 메뉴 구조
const menuItems = [
  {
    key: '/',
    icon: <HomeOutlined />,
    label: '홈',
  },
  {
    key: 'master',
    icon: <FileTextOutlined />,
    label: '마스터 관리',
    children: [
      { key: '/master/docs', label: '문서 관리' },
      { key: '/master/chapters', label: '챕터 관리' },
      { key: '/master/tables', label: '테이블 관리' },
      { key: '/master/charts', label: '차트 관리' },
      { key: '/master/sentences', label: '문장 관리' },
    ],
  },
  {
    key: 'data',
    icon: <DatabaseOutlined />,
    label: '데이터 관리',
    children: [
      { key: '/master/datas_db', label: 'DB 데이터' },
      { key: '/master/datas_ex', label: 'Excel 데이터' },
      { key: '/master/datas_ai', label: 'AI 데이터' },
    ],
  },
  {
    key: 'ai',
    icon: <RobotOutlined />,
    label: 'AI 생성',
    children: [
      { key: '/ai/charts', label: '차트 생성' },
      { key: '/ai/sentences', label: '문장 생성' },
      { key: '/ai/tables', label: '테이블 생성' },
    ],
  },
  {
    key: 'req',
    icon: <SendOutlined />,
    label: '문서 요청',
    children: [
      { key: '/req/list', label: '요청 목록' },
      { key: '/req/write', label: '문서 작성' },
    ],
  },
  {
    key: 'settings',
    icon: <SettingOutlined />,
    label: '설정',
    children: [
      { key: '/settings/servers', label: '서버 관리' },
      { key: '/settings/projects', label: '프로젝트 관리' },
      { key: '/settings/tenants', label: '테넌트 관리' },
    ],
  },
]

export default function AppLayout() {
  const [collapsed, setCollapsed] = useState(false)
  const navigate = useNavigate()
  const location = useLocation()
  const { token: cssToken } = theme.useToken()
  const { user, clearAuth } = useAuthStore()

  const handleMenuClick = ({ key }) => {
    navigate(key)
  }

  const handleLogout = () => {
    clearAuth()
    navigate('/login')
  }

  const userMenuItems = [
    {
      key: 'myinfo',
      icon: <UserOutlined />,
      label: '내 정보',
      onClick: () => navigate('/myinfo'),
    },
    { type: 'divider' },
    {
      key: 'logout',
      icon: <LogoutOutlined />,
      label: '로그아웃',
      onClick: handleLogout,
    },
  ]

  return (
    <Layout style={{ minHeight: '100vh' }}>
      <Sider
        trigger={null}
        collapsible
        collapsed={collapsed}
        width={220}
        style={{
          background: cssToken.colorBgContainer,
          borderRight: `1px solid ${cssToken.colorBorderSecondary}`,
          overflow: 'auto',
          height: '100vh',
          position: 'fixed',
          left: 0,
          top: 0,
          bottom: 0,
        }}
      >
        {/* 로고 영역 */}
        <div
          style={{
            height: 64,
            display: 'flex',
            alignItems: 'center',
            justifyContent: collapsed ? 'center' : 'flex-start',
            padding: collapsed ? 0 : '0 16px',
            borderBottom: `1px solid ${cssToken.colorBorderSecondary}`,
          }}
        >
          {collapsed ? (
            <FileTextOutlined style={{ fontSize: 24, color: cssToken.colorPrimary }} />
          ) : (
            <Text strong style={{ fontSize: 16, color: cssToken.colorPrimary }}>
              Smart Document
            </Text>
          )}
        </div>

        <Menu
          mode="inline"
          selectedKeys={[location.pathname]}
          defaultOpenKeys={['master', 'data', 'ai', 'req']}
          items={menuItems}
          onClick={handleMenuClick}
          style={{ border: 'none', marginTop: 8 }}
        />
      </Sider>

      <Layout style={{ marginLeft: collapsed ? 80 : 220, transition: 'margin 0.2s' }}>
        {/* 헤더 */}
        <Header
          style={{
            padding: '0 16px',
            background: cssToken.colorBgContainer,
            borderBottom: `1px solid ${cssToken.colorBorderSecondary}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            position: 'sticky',
            top: 0,
            zIndex: 1,
          }}
        >
          <span
            onClick={() => setCollapsed(!collapsed)}
            style={{ fontSize: 18, cursor: 'pointer', color: cssToken.colorText }}
          >
            {collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
          </span>

          <Dropdown menu={{ items: userMenuItems }} placement="bottomRight">
            <Space style={{ cursor: 'pointer' }}>
              <Avatar icon={<UserOutlined />} style={{ backgroundColor: cssToken.colorPrimary }} />
              {!collapsed && (
                <Text>{user?.email ?? '사용자'}</Text>
              )}
            </Space>
          </Dropdown>
        </Header>

        {/* 콘텐츠 */}
        <Content
          style={{
            margin: '24px 16px',
            padding: 24,
            background: cssToken.colorBgContainer,
            borderRadius: cssToken.borderRadius,
            minHeight: 'calc(100vh - 64px - 48px - 69px)',
          }}
        >
          <Outlet />
        </Content>

        <Footer style={{ textAlign: 'center', color: cssToken.colorTextSecondary }}>
          Smart Document ©{new Date().getFullYear()}
        </Footer>
      </Layout>
    </Layout>
  )
}
