import { create } from 'zustand'
import { persist } from 'zustand/middleware'

/**
 * 인증 스토어
 * Stage 2에서 실제 Supabase 로그인/로그아웃 액션이 추가된다.
 */
export const useAuthStore = create(
  persist(
    (set) => ({
      accessToken: null,
      refreshToken: null,
      user: null,
      tenantId: null,

      setAuth: ({ accessToken, refreshToken, user, tenantId }) =>
        set({ accessToken, refreshToken, user, tenantId }),

      clearAuth: () =>
        set({ accessToken: null, refreshToken: null, user: null, tenantId: null }),

      isAuthenticated: () => {
        // zustand persist는 getState()로 접근
        return !!useAuthStore.getState().accessToken
      },
    }),
    {
      name: 'smart-doc-auth',
      partialize: (state) => ({
        accessToken: state.accessToken,
        refreshToken: state.refreshToken,
        user: state.user,
        tenantId: state.tenantId,
      }),
    },
  ),
)
